// Proxy WebSocket that runs the actual socket inside a Worker thread.
// On iOS Safari / WKWebView, the 'open' event is deferred while the main
// thread has active timers. Moving the socket to a Worker gives it an
// independent event loop that iOS does not throttle.
export class WorkerWebSocket {
    static CONNECTING = 0;
    static OPEN       = 1;
    static CLOSING    = 2;
    static CLOSED     = 3;

    readonly url: string;
    binaryType: string = 'arraybuffer';
    readyState: number = 0;

    onopen:    ((ev: Event) => void) | null = null;
    onclose:   ((ev: CloseEvent) => void) | null = null;
    onerror:   ((ev: Event) => void) | null = null;
    onmessage: ((ev: MessageEvent) => void) | null = null;

    private _worker: Worker;
    private _port: MessagePort;
    private _listeners: Record<string, Function[]> = {};

    constructor(url: string, protocols?: string | string[]) {
        this.url = url;
        this._worker = new Worker('/mobile/ws-worker.js');
        const mc = new MessageChannel();
        this._port = mc.port1;
        mc.port1.onmessage = (e: MessageEvent): void => this._recv(e.data);
        this._worker.postMessage({ type: 'connect', url, protocols }, [mc.port2]);
    }

    private _recv(msg: { type: string; code?: number; reason?: string; data?: ArrayBuffer }): void {
        if (msg.type === 'open') {
            this.readyState = WorkerWebSocket.OPEN;
            const ev = new Event('open');
            if (this.onopen) this.onopen(ev);
            this._fire('open', ev);
        } else if (msg.type === 'message') {
            const ev = new MessageEvent('message', { data: msg.data });
            if (this.onmessage) this.onmessage(ev);
            this._fire('message', ev);
        } else if (msg.type === 'close') {
            this.readyState = WorkerWebSocket.CLOSED;
            const ev = new CloseEvent('close', { code: msg.code, reason: msg.reason });
            if (this.onclose) this.onclose(ev);
            this._fire('close', ev);
            this._worker.terminate();
        } else if (msg.type === 'error') {
            this.readyState = WorkerWebSocket.CLOSED;
            const ev = new Event('error');
            if (this.onerror) this.onerror(ev);
            this._fire('error', ev);
        }
    }

    private _fire(type: string, ev: Event): void {
        (this._listeners[type] ?? []).forEach((fn): void => { fn(ev); });
    }

    addEventListener(type: string, fn: Function): void {
        (this._listeners[type] ??= []).push(fn);
    }

    removeEventListener(type: string, fn: Function): void {
        if (this._listeners[type]) {
            this._listeners[type] = this._listeners[type].filter((f): boolean => f !== fn);
        }
    }

    send(data: Uint8Array): void {
        // data is always from src.slice(0,len) so it has its own fresh buffer
        this._port.postMessage({ type: 'send', data: data.buffer }, [data.buffer as ArrayBuffer]);
    }

    close(): void {
        this.readyState = WorkerWebSocket.CLOSING;
        this._port.postMessage({ type: 'close' });
        this._worker.terminate();
    }
}

export default class ClientStream {
    private readonly socket: WebSocket;
    private readonly wsin: WebSocketReader;
    private readonly wsout: WebSocketWriter;

    private closed: boolean = false;
    private ioerror: boolean = false;

    static async openSocket(host: string, secured: boolean): Promise<WebSocket> {
        return await new Promise<WebSocket>((resolve, reject): void => {
            const protocol: string = secured ? 'wss' : 'ws';
            const url: string = `${protocol}://${host}`;

            // On iOS Safari / WKWebView the main thread's timers prevent the 'open'
            // event from being delivered. Use a Worker so the socket lives on a
            // thread whose event loop iOS does not throttle.
            const isIosSafari: boolean = /iPad|iPhone|iPod/.test(navigator.userAgent) &&
                !/CriOS|FxiOS|EdgiOS/.test(navigator.userAgent);
            const ws: WorkerWebSocket | WebSocket = isIosSafari
                ? new WorkerWebSocket(url, 'binary')
                : new WebSocket(url, 'binary');

            if (ws.readyState === WebSocket.OPEN) {
                resolve(ws as WebSocket);
                return;
            }

            let settled = false;
            let giveUp: ReturnType<typeof setTimeout>;

            const done = (fn: () => void): void => {
                if (settled) return;
                settled = true;
                clearTimeout(giveUp);
                fn();
            };

            ws.addEventListener('open', (): void => done(() => resolve(ws as WebSocket)));
            ws.addEventListener('error', (): void => done(() => reject(ws)));
            ws.addEventListener('close', (): void => done(() => reject(ws)));

            giveUp = setTimeout((): void => done(() => reject(new Error('timeout'))), 30000);
        });
    }

    constructor(socket: WebSocket) {
        socket.onclose = this.onclose;
        socket.onerror = this.onerror;
        this.wsin = new WebSocketReader(socket, 5000);
        this.wsout = new WebSocketWriter(socket, 5000);
        this.socket = socket;
    }

    get host(): string {
        return this.socket.url.split('/')[2];
    }

    get port(): number {
        return parseInt(this.socket.url.split(':')[2], 10);
    }

    // todo: Java throws IOException on failure
    get available(): number {
        return this.closed ? 0 : this.wsin.available;
    }

    // todo: Java throws IOException on failure
    write(src: Uint8Array, len: number): void {
        if (!this.closed) {
            this.wsout.write(src, len);
        }
    }

    // todo: Java throws IOException on failure
    async read(): Promise<number> {
        return this.closed ? 0 : await this.wsin.read();
    }

    // todo: Java throws IOException on failure
    async readBytes(dst: Uint8Array, off: number, len: number): Promise<void> {
        if (this.closed) {
            return;
        }

        await this.wsin.readBytes(dst, off, len);
    }

    close(): void {
        this.closed = true;
        this.socket.close();
        this.wsin.close();
        this.wsout.close();
    }

    private onclose = (_event: CloseEvent): void => {
        if (this.closed) {
            return;
        }

        this.close();
    };

    private onerror = (_event: Event): void => {
        if (this.closed) {
            return;
        }

        this.ioerror = true;
        this.close();
    };
}

class WebSocketWriter {
    private readonly socket: WebSocket;
    private readonly limit: number;

    private closed: boolean = false;
    private ioerror: boolean = false;

    constructor(socket: WebSocket, limit: number) {
        this.socket = socket;
        this.limit = limit;
    }

    write(src: Uint8Array, len: number): void {
        if (this.closed) {
            return;
        }
        if (this.ioerror) {
            this.ioerror = false;
            throw new Error();
        }
        if (len > this.limit || src.length > this.limit) {
            throw new Error();
        }
        try {
            this.socket.send(src.slice(0, len));
        } catch (_e) {
            this.ioerror = true;
        }
    }

    close(): void {
        this.closed = true;
    }
}

class WebSocketEvent {
    private readonly bytes: Uint8Array;
    private position: number;

    constructor(bytes: Uint8Array) {
        this.bytes = bytes;
        this.position = 0;
    }

    get available(): number {
        return this.bytes.length - this.position;
    }

    get read(): number {
        return this.bytes[this.position++];
    }

    get len(): number {
        return this.bytes.length;
    }
}

class WebSocketReader {
    private readonly limit: number;

    private queue: WebSocketEvent[] = [];
    private event: WebSocketEvent | null = null;
    private callback: ((data: WebSocketEvent) => void) | null = null;
    private closed: boolean = false;
    private total: number = 0;

    constructor(socket: WebSocket, limit: number) {
        this.limit = limit;
        socket.binaryType = 'arraybuffer';
        socket.onmessage = this.onmessage;
    }

    get available(): number {
        return this.total;
    }

    private onmessage = (e: MessageEvent): void => {
        if (this.closed) {
            throw new Error();
        }

        const event: WebSocketEvent = new WebSocketEvent(new Uint8Array(e.data));

        this.total += event.available;

        if (this.callback) {
            const cb = this.callback;
            this.callback = null;
            cb(event);
        } else {
            this.queue.push(event);
        }
    };

    async read(): Promise<number> {
        if (this.closed) {
            throw new Error();
        }
        return await Promise.race([
            new Promise<number>(resolve => {
                if (!this.event || this.event.available === 0) {
                    this.event = this.queue.shift() ?? null;
                }
                if (this.event && this.event.available > 0) {
                    resolve(this.event.read);
                    this.total--;
                } else {
                    this.callback = (event: WebSocketEvent) => {
                        this.event = event;
                        this.total--;
                        resolve(event.read);
                    };
                }
            }),
            new Promise<number>((_, reject) => {
                setTimeout(() => {
                    if (this.closed) {
                        reject(new Error());
                    } else {
                        reject(new Error());
                    }
                }, 20000);
            })
        ]);
    }

    async readBytes(dst: Uint8Array, off: number, len: number): Promise<Uint8Array> {
        if (this.closed) {
            throw new Error();
        }
        for (let i = 0; i < len; i++) {
            dst[off + i] = await this.read();
        }
        return dst;
    }

    close(): void {
        this.closed = true;
        this.callback = null;
        this.event = null;
        this.queue = [];
    }
}
